powershell -NoProfile -Command '
$basePath = "G:\Meu Drive\CAPPELIN - JURIDICO - CLIENTES\SUPERENDIVIDAMENTO"
$revisarPath = "$basePath\REVISAR"

# Coletar todos os arquivos (excluindo a pasta REVISAR)
$arquivos = Get-ChildItem $basePath -Recurse -File | Where-Object { $_.DirectoryName -notlike "*\REVISAR*" }

# Agrupar por Nome + Tamanho para encontrar duplicatas REAIS
$grupos = $arquivos | Group-Object { "$($_.Name)|$($_.Length)" } | Where-Object { $_.Count -gt 1 }

Write-Host "Duplicatas reais encontradas (mesmo nome + mesmo tamanho): $($grupos.Count) grupos"
Write-Host ""

$clientesAfetados = @{}
$totalMovidos = 0

foreach ($grupo in $grupos) {
    # Ordenar por data (mais recente primeiro) e por padrÃĢo de cÃģpia (priorizar mover os com (1), (2), CÃģpia)
    $ordenados = $grupo.Group | Sort-Object @{E={$_.Name -match "\(1\)|\(2\)|\(3\)|\(4\)|\(5\)|C[oÃģ]pia|copia"}; Descending=$true}, LastWriteTime

    # Manter o Ãšltimo (mais recente sem padrÃĢo de cÃģpia) e mover os outros
    $manter = $ordenados | Select-Object -Last 1
    $mover = $ordenados | Select-Object -First ($ordenados.Count - 1)

    foreach ($arq in $mover) {
        # Extrair nome do cliente
        $relPath = $arq.DirectoryName -replace [regex]::Escape($basePath), ""
        $cliente = if ($relPath -match "^\\([^\\]+)") { $matches[1] } else { "(Raiz)" }

        # Criar nome Ãšnico para evitar conflitos na pasta REVISAR
        $novoNome = "$($arq.BaseName)_DE_$($cliente -replace ''[\\/:*?\"<>|]'', ''_'')$($arq.Extension)"
        $destino = Join-Path $revisarPath $novoNome

        # Se jÃĄ existe, adicionar timestamp
        if (Test-Path $destino) {
            $novoNome = "$($arq.BaseName)_DE_$($cliente -replace ''[\\/:*?\"<>|]'', ''_'')_$((Get-Date).Ticks)$($arq.Extension)"
            $destino = Join-Path $revisarPath $novoNome
        }

        try {
            Move-Item -Path $arq.FullName -Destination $destino -Force -ErrorAction Stop
            $totalMovidos++
            if (-not $clientesAfetados.ContainsKey($cliente)) {
                $clientesAfetados[$cliente] = 0
            }
            $clientesAfetados[$cliente]++
        } catch {
            Write-Host "Erro ao mover: $($arq.Name) - $($_.Exception.Message)"
        }
    }
}

Write-Host "=========================================="
Write-Host "CLIENTES COM ARQUIVOS MOVIDOS:"
Write-Host "=========================================="
