    Write-Host "  $($_.Key): $($_.Value) arquivo(s)"
}
Write-Host ""
Write-Host "=========================================="
Write-Host "TOTAL DE ARQUIVOS MOVIDOS: $totalMovidos"
Write-Host "=========================================="
'

