        } else {
            Write-Host "Executando desinstalador padrÃĢo..."
            Start-Process cmd -ArgumentList "/c `"$uninstall`" --quiet" -Wait -NoNewWindow
        }
    }
    Write-Host ""
    Write-Host "â Docker Desktop desinstalado!"
} else {
    Write-Host "Docker Desktop nÃĢo encontrado no registro"
